(1241, 'ERROR', 2, '68.227.72.45', '/accounting/modules/bms/invoices_addedit.php\n-420: Database Error\n\nYou have an error in your SQL syntax; check the manual that corresponds to your MySQL server version for the right syntax to use near \'s Machine\',<br />							1,<br />							0,<br />							0,<br />							95,<br />							2,<br />							0,<br />							\' at line 20<br /><br />Statement: <br />						INSERT INTO<br />							lineitems(<br />								invoiceid, <br />								productid, <br />								memo,<br />								taxable, <br />								unitweight,<br />								unitcost,<br />								unitprice,<br />								quantity,<br />								displayorder,<br />								createdby,<br />								creationdate,<br />								modifiedby,<br />								modifieddate<br />							)<br />						VALUES (<br />							1179,<br />							12,<br />							\'Labor Hour, $95.00 Virus Removal Ziggy\'s Machine\',<br />							1,<br />							0,<br />							0,<br />							95,<br />							2,<br />							0,<br />							2,<br />							NOW(),<br />							2,<br />							NOW()							<br />						)', '2013-10-04 22:25:09'),
