(1245, 'ERROR', 2, '166.194.200.5', '/accounting/search.php?id=3\n-420: Database Error\n\nYou have an error in your SQL syntax; check the manual that corresponds to your MySQL server version for the right syntax to use near \') AND invoices.type=\'Order\' AND readytopost = 1\' at line 15<br /><br />Statement: <br />				SELECT<br />					invoices.id,<br />					invoices.clientid,<br />					invoices.totalti,<br />					invoices.invoicedate,<br />					paymentmethods.type,<br />					invoices.ccnumber,<br />					invoices.ccexpiration,<br />					invoices.ccverification,<br />					invoices.routingnumber,<br />					invoices.accountnumber<br />				FROM<br />					invoices LEFT JOIN paymentmethods ON invoices.paymentmethodid = paymentmethods.id<br />				WHERE<br />					( invoices.id=) AND invoices.type=\'Order\' AND readytopost = 1', '2024-04-27 13:57:27');
