(1, 'Base', 'base', 'The basic phpBMS framkework.  This is the minimum module required in order for the web applicatoin to work.', '0.96'),
(2, 'BMS Module', 'bms', 'The Business Magagement functionality of phpBMS.  This module includes clients/propsetcs, quote/order/invoice, and products sections.', '0.96'),
