(1, 'Raw Table Print', 'report', 0, 0, 30, 'report/general_tableprint.php', 'This report will prints out of every field for the table for the given records.  The report is displayed HTML format.', 1, '2009-04-13 10:45:30', 1, '2009-04-13 15:45:30'),
(2, 'Raw Table Export', 'export', 0, 0, 30, 'report/general_export.php', 'This report will generate a tab-delimited text file. Values are encapsulated in quotes, and the first line lists the field names.', 1, '2009-04-13 10:45:30', 1, '2009-04-13 15:45:30'),
(3, 'Note Summary', 'PDF Report', 12, 50, 0, 'modules/base/report/notes_summary.php', 'PDF report giving basic note information (subject,dates,content) .  By deault, the notes are shown in chronological order.', 1, '2009-04-13 10:45:30', 1, '2009-04-13 15:45:30'),
