(200, 'Invoice', 'PDF Report', 3, 100, 0, 'modules/bms/report/invoices_pdfinvoice.php', 'This report will gerneate and display an invoice in PDF format (which can be printed or saved).  The PDF file will contain one page per invoice.', 1, '2009-04-13 10:46:43', 1, '2009-04-13 15:46:43'),
(201, 'Work Order', 'PDF Report', 3, 100, 20, 'modules/bms/report/invoices_pdfworkorder.php', 'This report will gerneate and display a work order  in PDF format (which can be printed or saved).  The PDF file will contain one page per work order.', 1, '2009-04-13 10:46:43', 1, '2009-04-13 15:46:43'),
(202, 'Packing List', 'PDF Report', 3, 100, 0, 'modules/bms/report/invoices_pdfpackinglist.php', 'This report will gerneate and display an invoice packing list in PDF format (which can be printed or saved).  The PDF file will contain one page per invoice packing list.', 1, '2009-04-13 10:46:43', 1, '2009-04-13 15:46:43'),
(203, 'Labels - Folder', 'PDF Report', 2, 50, 0, 'modules/bms/report/clients_folderlabels.php', 'Avery 5160 or compatible (3x10) Instructor Folder labels. \r\n\r\n **MAKE SURE when printing the pdf file, to TURN OFF the option \"shrink oversized pages to paper size\".**', 1, '2009-04-13 10:46:43', 1, '2009-04-13 15:46:43'),
